const items = $input.all().map(i => i.json);

return items.map(item => {
  const urgency = item.alert_type === 'gate_review_today' ? '🔴'
    : item.alert_type === 'gate_review_overdue' ? '🟠'
    : item.alert_type === 'proposal_deadline_soon' ? '🟡'
    : item.alert_type === 'capture_stale' ? '⚪'
    : '🔵';

  const typeLabel = {
    gate_review_today: 'GATE REVIEW TODAY',
    gate_review_week: 'Gate Review This Week',
    gate_review_overdue: 'GATE REVIEW OVERDUE',
    proposal_deadline_soon: 'Proposal Deadline Soon',
    capture_stale: 'Capture Plan Stale (14+ days)'
  }[item.alert_type] || 'Milestone Alert';

  const lines = [
    `${urgency} *${typeLabel}*`,
    `*${item.opp_name || item.opp_title}*`,
    `Agency: ${item.agency || 'N/A'}`,
    `Gate: ${item.gate_stage || 'N/A'}`,
    item.gate_review_date ? `Gate Review: ${item.gate_review_date}` : null,
    item.days_to_proposal != null ? `Proposal in ${item.days_to_proposal} days (${item.response_deadline})` : null,
    item.pwin ? `Pwin: ${item.pwin}%` : null,
    item.capture_manager ? `CM: ${item.capture_manager}` : null,
    item.teaming_partner ? `Partner: ${item.teaming_partner}` : null,
    item.estimated_value ? `Value: $${(parseFloat(item.estimated_value)/1e6).toFixed(1)}M` : null
  ].filter(Boolean).join('\n');

  return { json: { ...item, telegram_message: lines } };
});
